using System;
using System.Collections.Generic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);

            // Setup TempData
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider(null));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student CreateStudent(string firstName = "John", string lastName = "Doe", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                FirstMidName = firstName,
                LastName = lastName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2020, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_FiltersBySearchString()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Smith", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByNameDescending()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Smith", model[0].LastName);
            Assert.Equal("Jones", model[1].LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            CreateStudent("Alice", "Smith", new DateTime(2021, 1, 1));
            CreateStudent("Bob", "Jones", new DateTime(2020, 1, 1));

            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Jones", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            CreateStudent("Alice", "Smith", new DateTime(2020, 1, 1));
            CreateStudent("Bob", "Jones", new DateTime(2021, 1, 1));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Jones", model[0].LastName);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index(null, "Smith", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_ResetsPageToOne_WhenNewSearchString()
        {
            CreateStudent("Alice", "Smith");

            var result = _controller.Index(null, null, "Smith", 5) as ViewResult;

            Assert.NotNull(result);
            // When searchString is not null, page resets to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            var student = CreateStudent();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult_WithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Students);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_Post_AddsModelError_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithStudent()
        {
            var student = CreateStudent();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var student = CreateStudent();
            student.LastName = "Updated";

            // Detach the tracked entity so the controller can attach it
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenEnrollmentDateInvalid()
        {
            var student = CreateStudent();
            student.EnrollmentDate = new DateTime(1000, 1, 1);

            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithStudent()
        {
            var student = CreateStudent();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudent_AndRedirects()
        {
            var student = CreateStudent();

            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Students);
        }

        [Fact]
        public void Index_SearchesByFirstName()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_Pagination_DefaultsToPageOne()
        {
            // Add 15 students (page size is 10)
            for (int i = 0; i < 15; i++)
            {
                CreateStudent($"Student{i}", $"Last{i}");
            }

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
            Assert.False(model.HasPreviousPage);
        }

        [Fact]
        public void Index_Pagination_ReturnsSecondPage()
        {
            for (int i = 0; i < 15; i++)
            {
                CreateStudent($"Student{i}", $"Last{i:D2}");
            }

            var result = _controller.Index(null, null, null, 2) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
            Assert.False(model.HasNextPage);
            Assert.True(model.HasPreviousPage);
        }
    }
}

