using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/webroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp/content");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider(null));

            SeedDepartment();
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department SeedDepartment()
        {
            var dept = _context.Departments.FirstOrDefault();
            if (dept != null) return dept;

            dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course CreateCourse(string title = "Test Course", int credits = 3, int? courseId = null)
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = courseId ?? new Random().Next(1000, 9999),
                Title = title,
                Credits = credits,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithListOfCourses()
        {
            CreateCourse("Chemistry", 3, 1050);
            CreateCourse("Physics", 4, 2050);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var course = CreateCourse("Chemistry", 3, 1050);

            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult_WithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 5001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
