using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider(null));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateInstructor(string firstName = "Kim", string lastName = "Abercrombie",
            DateTime? hireDate = null, bool withOffice = false, bool withCourses = false)
        {
            var instructor = new Instructor
            {
                FirstMidName = firstName,
                LastName = lastName,
                HireDate = hireDate ?? new DateTime(2000, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            if (withOffice)
            {
                instructor.OfficeAssignment = new OfficeAssignment
                {
                    Location = "Smith 17"
                };
            }

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            if (withCourses)
            {
                var dept = new Department
                {
                    Name = "TestDept",
                    Budget = 100000,
                    StartDate = new DateTime(2020, 1, 1)
                };
                _context.Departments.Add(dept);
                _context.SaveChanges();

                var course = new Course
                {
                    CourseID = new Random().Next(1000, 99999),
                    Title = "Test Course",
                    Credits = 3,
                    DepartmentID = dept.DepartmentID,
                    Enrollments = new List<Enrollment>()
                };
                _context.Courses.Add(course);
                _context.SaveChanges();

                var assignment = new CourseAssignment
                {
                    InstructorID = instructor.ID,
                    CourseID = course.CourseID
                };
                _context.CourseAssignments.Add(assignment);
                _context.SaveChanges();

                // Reload to get navigation properties
                _context.Entry(instructor).Collection(i => i.CourseAssignments).Load();
            }

            return instructor;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            CreateInstructor("Kim", "Abercrombie", withOffice: true, withCourses: true);

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = CreateInstructor("Kim", "Abercrombie", withCourses: true);

            var result = _controller.Index(instructor.ID, null) as ViewResult;

