using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal(new DateTime(2020, 9, 1), retrieved.EnrollmentDate);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(2000, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Abercrombie");
            Assert.Equal("Kim", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(1050);
            Assert.NotNull(retrieved);
            Assert.Equal("Chemistry", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "Mathematics",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Mathematics");
            Assert.Equal(200000, retrieved.Budget);
        }

        [Fact]
        public void CanAddEnrollment_WithRelationships()
        {
            var student = new Student
            {
                FirstMidName = "A",
                LastName = "B",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            _context.Students.Add(student);

            var dept = new Department
            {
                Name = "Dept",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 2001,
                Title = "Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();
            Assert.Equal("B", retrieved.Student.LastName);
            Assert.Equal("Course", retrieved.Course.Title);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Inst",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "Dept",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 3001,
                Title = "Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_HasInstructorIdAsKey()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Office",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Room 101", retrieved.Location);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Student created",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("CREATE", retrieved.Operation);
        }
    }
}

