        public void Index_SearchesByFirstName()
        {
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_Pagination_DefaultsToPageOne()
        {
            for (int i = 0; i < 15; i++)
            {
                CreateStudent($"Student{i}", $"Last{i}");
