using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider(null));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateInstructor(string firstName = "Kim", string lastName = "Abercrombie")
        {
            var instructor = new Instructor
            {
                FirstMidName = firstName,
                LastName = lastName,
                HireDate = new DateTime(2000, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Department CreateDepartment(string name = "Engineering", decimal budget = 100000, int? instructorId = null)
        {
            var dept = new Department
            {
                Name = name,
                Budget = budget,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructorId
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithListOfDepartments()
        {
            CreateDepartment("Math");
            CreateDepartment("Science");

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            var dept = CreateDepartment("Physics");

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Physics", model.Name);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var dept = new Department
            {
                Name = "New Dept",
                Budget = 50000,
                StartDate = new DateTime(2021, 1, 1)
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Departments);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { Budget = 50000, StartDate = new DateTime(2021, 1, 1) };

            var result = _controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Edit((int?)999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithDepartment()
        {
            var dept = CreateDepartment("Math");

            var result = _controller.Edit((int?)dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Math", model.Name);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var dept = CreateDepartment("Math");
            dept.Name = "Advanced Math";

            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = ((ActionResult)_controller.Edit(dept)) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                Budget = 50000,
                StartDate = new DateTime(2021, 1, 1)
            };

            var result = ((ActionResult)_controller.Edit(dept)) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithDepartment()
        {
            var dept = CreateDepartment("Chemistry");

            var result = _controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Chemistry", model.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_AndRedirects()
        {
            var dept = CreateDepartment("Obsolete");

            var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Departments);
        }

        [Fact]
        public void Create_Post_SendsNotification()
        {
            var dept = new Department
            {
                Name = "Notify Dept",
                Budget = 50000,
                StartDate = new DateTime(2021, 1, 1)
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Index_IncludesAdministrator()
        {
            var instructor = CreateInstructor();
            CreateDepartment("Managed Dept", 100000, instructor.ID);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Single(model);
        }
    }
}
